window.PARASITIC_QUESTIONS.push(...[{"id":"Q101","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Treatment","difficulty":"Easy","source":"PDF p. 172","question":{"en":"Which instruction is essential when applying permethrin 5% for classic scabies in an adult?","ar":"أي تعليمات أساسية عند استخدام بيرمثرين 5% للجرب التقليدي لدى بالغ؟"},"options":[{"letter":"A","en":"Cover the entire body from neck to soles, including under nails, and wash after 8–14 hours","ar":"تغطية كامل الجسم من العنق إلى الأخمصين بما في ذلك تحت الأظافر ثم الغسل بعد 8–14 ساعة"},{"letter":"B","en":"Apply only to the itchiest papules for 30 minutes","ar":"وضعه على أكثر الحطاطات حكة فقط لمدة 30 دقيقة"},{"letter":"C","en":"Use it as an oral solution","ar":"استخدامه كمحلول فموي"},{"letter":"D","en":"Avoid treating genital and flexural areas","ar":"تجنب علاج المناطق التناسلية والثنيات"}],"correct":"A","explanation":{"en":"Whole-body coverage is required because mites may be present beyond visible lesions.","ar":"يلزم تغطية الجسم كاملًا لأن العث قد يوجد خارج الآفات الظاهرة."},"reasoning":{"en":"The decisive clue is correct surface coverage and contact time. This supports Cover the entire body from neck to soles, including under nails, and wash after 8–14 hours and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي تغطية السطح الصحيحة ومدة التلامس؛ ولذلك تدعم الإجابة «تغطية كامل الجسم من العنق إلى الأخمصين بما في ذلك تحت الأظافر ثم الغسل بعد 8–14 ساعة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q102","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Treatment","difficulty":"Easy","source":"PDF p. 172","question":{"en":"When is a second permethrin application commonly advised?","ar":"متى يُنصح غالبًا بتطبيق ثانٍ للبيرمثرين؟"},"options":[{"letter":"A","en":"Every hour on the first day","ar":"كل ساعة في اليوم الأول"},{"letter":"B","en":"About 7–14 days after the first application","ar":"بعد نحو 7–14 يومًا من التطبيق الأول"},{"letter":"C","en":"Only after one year","ar":"بعد سنة فقط"},{"letter":"D","en":"Never, even if required by the regimen","ar":"لا يُكرر أبدًا"}],"correct":"B","explanation":{"en":"Repeating treatment targets mites that hatch after the initial application.","ar":"يستهدف تكرار العلاج العث الذي يفقس بعد التطبيق الأول."},"reasoning":{"en":"The decisive clue is the mite egg-hatching cycle. This supports About 7–14 days after the first application and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي دورة فقس بيض العث؛ ولذلك تدعم الإجابة «بعد نحو 7–14 يومًا من التطبيق الأول» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q103","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Treatment","difficulty":"Easy","source":"PDF p. 174","question":{"en":"A patient with severe crusted scabies needs the most intensive listed regimen. Which oral ivermectin schedule is appropriate?","ar":"مريض لديه جرب متقشر شديد يحتاج أكثر نظام مكثف مذكور. أي جدول للإيفرمكتين الفموي مناسب؟"},"options":[{"letter":"A","en":"One dose only without topical therapy","ar":"جرعة واحدة فقط دون علاج موضعي"},{"letter":"B","en":"Daily for one year","ar":"يوميًا لمدة سنة"},{"letter":"C","en":"200 mcg/kg on days 1, 2, 8, 9, 15, 22, and 29 with topical permethrin","ar":"200 ميكروجرام/كجم في الأيام 1 و2 و8 و9 و15 و22 و29 مع البيرمثرين الموضعي"},{"letter":"D","en":"A topical antihistamine alone","ar":"مضاد هيستامين موضعي فقط"}],"correct":"C","explanation":{"en":"The seven-dose schedule is used for the most severe hyperinfestation alongside repeated topical treatment.","ar":"يُستخدم جدول السبع جرعات في أشد حالات فرط الإصابة مع تكرار العلاج الموضعي."},"reasoning":{"en":"The decisive clue is severe crusted disease requiring combined intensive therapy. This supports 200 mcg/kg on days 1, 2, 8, 9, 15, 22, and 29 with topical permethrin and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي مرض متقشر شديد يحتاج علاجًا مركبًا مكثفًا؛ ولذلك تدعم الإجابة «200 ميكروجرام/كجم في الأيام 1 و2 و8 و9 و15 و22 و29 مع البيرمثرين الموضعي» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q104","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Treatment","difficulty":"Medium","source":"PDF p. 174","question":{"en":"Why may urea 10% cream be added in crusted scabies?","ar":"لماذا قد يُضاف كريم يوريا 10% في الجرب المتقشر؟"},"options":[{"letter":"A","en":"To replace all antiparasitic treatment","ar":"لاستبدال كل العلاج المضاد للطفيليات"},{"letter":"B","en":"To induce mite reproduction","ar":"لتحفيز تكاثر العث"},{"letter":"C","en":"To stain the burrows","ar":"لتلوين الأنفاق"},{"letter":"D","en":"To soften hyperkeratotic crusts and improve penetration of scabicides","ar":"لتليين القشور مفرطة التقرن وتحسين اختراق الأدوية القاتلة للجرب"}],"correct":"D","explanation":{"en":"Keratolysis helps topical permethrin reach mites beneath thick scale.","ar":"يساعد تقشير الكيراتين البيرمثرين الموضعي على الوصول إلى العث تحت القشور السميكة."},"reasoning":{"en":"The decisive clue is thick crusts blocking drug penetration. This supports To soften hyperkeratotic crusts and improve penetration of scabicides and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي القشور السميكة التي تعيق اختراق الدواء؛ ولذلك تدعم الإجابة «لتليين القشور مفرطة التقرن وتحسين اختراق الأدوية القاتلة للجرب» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q105","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Treatment","difficulty":"Medium","source":"PDF p. 174","question":{"en":"What is the preferred first-line treatment for scabies during pregnancy?","ar":"ما علاج الخط الأول المفضل للجرب أثناء الحمل؟"},"options":[{"letter":"A","en":"Permethrin 5% cream","ar":"كريم بيرمثرين 5%"},{"letter":"B","en":"Oral ivermectin","ar":"إيفرمكتين فموي"},{"letter":"C","en":"Lindane","ar":"ليندان"},{"letter":"D","en":"No treatment until delivery","ar":"تأجيل العلاج حتى الولادة"}],"correct":"A","explanation":{"en":"Permethrin combines high efficacy with minimal systemic absorption.","ar":"يجمع البيرمثرين بين الفعالية العالية والامتصاص الجهازي المحدود."},"reasoning":{"en":"The decisive clue is pregnancy safety and efficacy. This supports Permethrin 5% cream and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الأمان والفعالية في الحمل؛ ولذلك تدعم الإجابة «كريم بيرمثرين 5%» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q106","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Treatment","difficulty":"Medium","source":"PDF p. 174","question":{"en":"What is the preferred treatment for scabies in a neonate younger than 2 months?","ar":"ما العلاج المفضل للجرب لدى حديث ولادة أصغر من شهرين؟"},"options":[{"letter":"A","en":"Oral ivermectin","ar":"إيفرمكتين فموي"},{"letter":"B","en":"Topical sulfur","ar":"الكبريت الموضعي"},{"letter":"C","en":"Spinosad","ar":"سبينوساد"},{"letter":"D","en":"Lindane","ar":"ليندان"}],"correct":"B","explanation":{"en":"Sulfur is a low-cost scabicidal and keratolytic option for this age group.","ar":"الكبريت خيار منخفض التكلفة قاتل للجرب ومقشر للكيراتين لهذه الفئة العمرية."},"reasoning":{"en":"The decisive clue is the infant is below the approved permethrin age. This supports Topical sulfur and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الرضيع دون العمر المعتمد للبيرمثرين؛ ولذلك تدعم الإجابة «الكبريت الموضعي» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q107","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Treatment","difficulty":"Medium","source":"PDF p. 175","question":{"en":"How should persistent itching be managed after mites have been eradicated?","ar":"كيف تُعالج الحكة المستمرة بعد القضاء على العث؟"},"options":[{"letter":"A","en":"Repeat scabicide daily indefinitely","ar":"تكرار قاتل الجرب يوميًا بلا نهاية"},{"letter":"B","en":"Use antibiotics in every patient","ar":"استخدام مضاد حيوي لكل مريض"},{"letter":"C","en":"Use oral antihistamines and, when appropriate, topical corticosteroids after eradication therapy","ar":"استخدام مضادات الهيستامين الفموية وعند الملاءمة كورتيكوستيرويد موضعي بعد علاج القضاء على العث"},{"letter":"D","en":"Ignore severe symptoms completely","ar":"تجاهل الأعراض الشديدة تمامًا"}],"correct":"C","explanation":{"en":"Post-scabetic hypersensitivity may persist and needs symptomatic anti-inflammatory treatment.","ar":"قد يستمر فرط الحساسية بعد الجرب ويحتاج علاجًا عرضيًا مضادًا للالتهاب."},"reasoning":{"en":"The decisive clue is no new burrows after successful eradication. This supports Use oral antihistamines and, when appropriate, topical corticosteroids after eradication therapy and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي عدم وجود أنفاق جديدة بعد القضاء الناجح؛ ولذلك تدعم الإجابة «استخدام مضادات الهيستامين الفموية وعند الملاءمة كورتيكوستيرويد موضعي بعد علاج القضاء على العث» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q108","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Treatment","difficulty":"Medium","source":"PDF p. 175","question":{"en":"Which treatment may help persistent nodular scabies after eradication?","ar":"أي علاج قد يفيد عقيدات الجرب المستمرة بعد القضاء على العث؟"},"options":[{"letter":"A","en":"Oral acyclovir","ar":"أسيكلوفير فموي"},{"letter":"B","en":"Malathion lotion","ar":"لوشن ملاثيون"},{"letter":"C","en":"Cryotherapy of every burrow","ar":"العلاج بالتبريد لكل نفق"},{"letter":"D","en":"Topical or intralesional corticosteroid, or tacrolimus","ar":"كورتيكوستيرويد موضعي أو داخل الآفة أو تاكروليمس"}],"correct":"D","explanation":{"en":"Persistent nodules are inflammatory hypersensitivity lesions rather than a reason for endless scabicide.","ar":"العقيدات المستمرة آفات التهابية من فرط الحساسية وليست سببًا لاستمرار قاتلات الجرب بلا نهاية."},"reasoning":{"en":"The decisive clue is persistent nodules after mite eradication. This supports Topical or intralesional corticosteroid, or tacrolimus and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي العقيدات المستمرة بعد القضاء على العث؛ ولذلك تدعم الإجابة «كورتيكوستيرويد موضعي أو داخل الآفة أو تاكروليمس» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q109","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Treatment","difficulty":"Medium","source":"PDF p. 175","question":{"en":"What contact-management step is necessary when one household member has scabies?","ar":"ما الإجراء اللازم للمخالطين عند إصابة فرد من الأسرة بالجرب؟"},"options":[{"letter":"A","en":"Treat close household and sexual contacts at the same time","ar":"علاج المخالطين المنزليين والجنسيين في الوقت نفسه"},{"letter":"B","en":"Treat only the person with the most visible rash","ar":"علاج صاحب أوضح طفح فقط"},{"letter":"C","en":"Wait until every contact develops burrows","ar":"الانتظار حتى تظهر أنفاق لكل مخالط"},{"letter":"D","en":"Use antibiotics prophylactically for all contacts","ar":"إعطاء مضادات حيوية وقائية للجميع"}],"correct":"A","explanation":{"en":"Simultaneous treatment prevents ping-pong reinfestation from asymptomatic contacts.","ar":"يمنع العلاج المتزامن إعادة العدوى المتبادلة من مخالطين بلا أعراض."},"reasoning":{"en":"The decisive clue is shared exposure with delayed incubation. This supports Treat close household and sexual contacts at the same time and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي التعرض المشترك مع حضانة متأخرة؛ ولذلك تدعم الإجابة «علاج المخالطين المنزليين والجنسيين في الوقت نفسه» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q110","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Treatment","difficulty":"Medium","source":"PDF p. 175","question":{"en":"A scabies patient has spreading cellulitis from excoriations. What additional therapy is required?","ar":"مريض جرب لديه التهاب نسيج خلوي منتشر بسبب الخدوش. ما العلاج الإضافي المطلوب؟"},"options":[{"letter":"A","en":"Scabicide alone regardless of cellulitis","ar":"قاتل الجرب وحده رغم التهاب النسيج"},{"letter":"B","en":"Appropriate systemic antibiotics in addition to scabies eradication","ar":"مضادات حيوية جهازية مناسبة بالإضافة إلى القضاء على الجرب"},{"letter":"C","en":"Antifungal nail lacquer","ar":"طلاء مضاد فطري للأظافر"},{"letter":"D","en":"HPV vaccine","ar":"لقاح HPV"}],"correct":"B","explanation":{"en":"The parasite and the bacterial complication must both be treated.","ar":"يجب علاج الطفيل والمضاعفة البكتيرية معًا."},"reasoning":{"en":"The decisive clue is clinical bacterial superinfection. This supports Appropriate systemic antibiotics in addition to scabies eradication and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي عدوى بكتيرية ثانوية سريرية؛ ولذلك تدعم الإجابة «مضادات حيوية جهازية مناسبة بالإضافة إلى القضاء على الجرب» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q111","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Treatment","difficulty":"Medium","source":"PDF p. 180","question":{"en":"What is the correct use of permethrin 1% for head lice?","ar":"ما الاستخدام الصحيح لبيرمثرين 1% لقمل الرأس؟"},"options":[{"letter":"A","en":"Leave it continuously for one week","ar":"تركه أسبوعًا متواصلًا"},{"letter":"B","en":"Apply only to clothing seams","ar":"وضعه على درزات الملابس فقط"},{"letter":"C","en":"Saturate the hair, leave for about 10 minutes, rinse, and repeat around day 9–10","ar":"تشبيع الشعر وتركه نحو 10 دقائق ثم شطفه والتكرار قرب اليوم 9–10"},{"letter":"D","en":"Take it orally","ar":"تناوله فمويًا"}],"correct":"C","explanation":{"en":"The repeat dose kills newly hatched lice because the product is not completely ovicidal.","ar":"تقتل الجرعة المتكررة القمل حديث الفقس لأن الدواء لا يقضي تمامًا على البيض."},"reasoning":{"en":"The decisive clue is the standard 10-minute application and timed repeat. This supports Saturate the hair, leave for about 10 minutes, rinse, and repeat around day 9–10 and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي التطبيق 10 دقائق والتكرار في موعده؛ ولذلك تدعم الإجابة «تشبيع الشعر وتركه نحو 10 دقائق ثم شطفه والتكرار قرب اليوم 9–10» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q112","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Treatment","difficulty":"Medium","source":"PDF p. 180","question":{"en":"A child has no live lice after permethrin but still has nits. What is the best next step?","ar":"لا يوجد قمل حي لدى طفل بعد البيرمثرين لكن ما زالت صئبان موجودة. ما الخطوة الأفضل؟"},"options":[{"letter":"A","en":"Immediately use three pesticides together","ar":"استخدام ثلاثة مبيدات فورًا"},{"letter":"B","en":"Exclude the child from school for months","ar":"منع الطفل من المدرسة أشهرًا"},{"letter":"C","en":"Give systemic antibiotics","ar":"إعطاء مضاد حيوي جهازي"},{"letter":"D","en":"Complete the scheduled repeat and use nit combing; do not assume failure from nits alone","ar":"إكمال التكرار المقرر مع تمشيط الصئبان وعدم افتراض الفشل بسبب الصئبان وحدها"}],"correct":"D","explanation":{"en":"Empty or nonviable nits may remain attached after successful treatment.","ar":"قد تبقى صئبان فارغة أو غير حية ملتصقة بعد نجاح العلاج."},"reasoning":{"en":"The decisive clue is absence of live crawling lice. This supports Complete the scheduled repeat and use nit combing; do not assume failure from nits alone and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي غياب القمل الحي المتحرك؛ ولذلك تدعم الإجابة «إكمال التكرار المقرر مع تمشيط الصئبان وعدم افتراض الفشل بسبب الصئبان وحدها» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q113","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Treatment","difficulty":"Medium","source":"PDF p. 181","question":{"en":"Which option is appropriate after correctly used pyrethroids fail because of suspected resistance?","ar":"أي خيار مناسب بعد فشل البيرثرويد المستخدم بصورة صحيحة بسبب مقاومة مشتبهة؟"},"options":[{"letter":"A","en":"Spinosad or topical ivermectin","ar":"سبينوساد أو إيفرمكتين موضعي"},{"letter":"B","en":"Increase permethrin concentration indefinitely","ar":"زيادة تركيز البيرمثرين بلا نهاية"},{"letter":"C","en":"Use lindane first in every child","ar":"استخدام ليندان أولًا لكل طفل"},{"letter":"D","en":"No further treatment","ar":"عدم إعطاء علاج آخر"}],"correct":"A","explanation":{"en":"Agents with different mechanisms can overcome pyrethroid-resistant lice.","ar":"قد تتغلب الأدوية ذات الآليات المختلفة على القمل المقاوم للبيرثرويد."},"reasoning":{"en":"The decisive clue is live lice after two correct pyrethroid applications. This supports Spinosad or topical ivermectin and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي قمل حي بعد تطبيقين صحيحين للبيرثرويد؛ ولذلك تدعم الإجابة «سبينوساد أو إيفرمكتين موضعي» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q114","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Treatment","difficulty":"Medium","source":"PDF p. 180","question":{"en":"Which instruction is essential when prescribing malathion for head lice?","ar":"أي تعليمات أساسية عند وصف الملاثيون لقمل الرأس؟"},"options":[{"letter":"A","en":"Use it beside a heater","ar":"استخدامه بجوار المدفأة"},{"letter":"B","en":"Apply to dry hair for 8–12 hours and avoid flames, cigarettes, and hot dryers","ar":"وضعه على الشعر الجاف 8–12 ساعة وتجنب اللهب والسجائر والمجففات الساخنة"},{"letter":"C","en":"Rinse after 30 seconds","ar":"شطفه بعد 30 ثانية"},{"letter":"D","en":"Use in every infant under 2 years","ar":"استخدامه لكل رضيع دون سنتين"}],"correct":"B","explanation":{"en":"Malathion is effective and partly ovicidal but its formulation is highly flammable.","ar":"الملاثيون فعال وله تأثير على البيض لكن تركيبته شديدة الاشتعال."},"reasoning":{"en":"The decisive clue is the extended application and fire hazard. This supports Apply to dry hair for 8–12 hours and avoid flames, cigarettes, and hot dryers and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي مدة التطبيق الطويلة وخطر الحريق؛ ولذلك تدعم الإجابة «وضعه على الشعر الجاف 8–12 ساعة وتجنب اللهب والسجائر والمجففات الساخنة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q115","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Treatment","difficulty":"Medium","source":"PDF p. 181","question":{"en":"How is topical ivermectin 0.5% lotion generally used for head lice?","ar":"كيف يُستخدم عادةً لوشن الإيفرمكتين الموضعي 0.5% لقمل الرأس؟"},"options":[{"letter":"A","en":"Apply intravenously","ar":"يُعطى وريديًا"},{"letter":"B","en":"Use daily for 12 weeks","ar":"يُستخدم يوميًا 12 أسبوعًا"},{"letter":"C","en":"Apply once to dry hair for 10 minutes, then rinse","ar":"يُوضع مرة على الشعر الجاف 10 دقائق ثم يُشطف"},{"letter":"D","en":"Apply only to the pillow","ar":"يوضع على الوسادة فقط"}],"correct":"C","explanation":{"en":"A single application often kills lice and prevents newly hatched nymphs from feeding.","ar":"غالبًا يقتل التطبيق الواحد القمل ويمنع الحوريات حديثة الفقس من التغذية."},"reasoning":{"en":"The decisive clue is the labeled single topical application. This supports Apply once to dry hair for 10 minutes, then rinse and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي التطبيق الموضعي الواحد المعتمد؛ ولذلك تدعم الإجابة «يُوضع مرة على الشعر الجاف 10 دقائق ثم يُشطف» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q116","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Treatment","difficulty":"Medium","source":"PDF p. 182","question":{"en":"What is the correct wet-combing schedule when chemical pediculicides are avoided?","ar":"ما جدول التمشيط الرطب الصحيح عند تجنب مبيدات القمل الكيميائية؟"},"options":[{"letter":"A","en":"Comb once for one minute","ar":"تمشيط مرة لدقيقة"},{"letter":"B","en":"Comb dry hair monthly","ar":"تمشيط الشعر الجاف شهريًا"},{"letter":"C","en":"Shave every family member","ar":"حلق شعر جميع أفراد الأسرة"},{"letter":"D","en":"Comb thoroughly with conditioner every 3–4 days for several weeks","ar":"تمشيط دقيق مع بلسم كل 3–4 أيام لعدة أسابيع"}],"correct":"D","explanation":{"en":"Repeated mechanical removal must span several louse life cycles.","ar":"يجب أن تمتد الإزالة الميكانيكية المتكررة عبر عدة دورات حياة للقمل."},"reasoning":{"en":"The decisive clue is multiple sessions covering newly hatched lice. This supports Comb thoroughly with conditioner every 3–4 days for several weeks and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي جلسات متعددة تغطي القمل حديث الفقس؛ ولذلك تدعم الإجابة «تمشيط دقيق مع بلسم كل 3–4 أيام لعدة أسابيع» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q117","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Treatment","difficulty":"Medium","source":"PDF p. 187","question":{"en":"What is the main treatment for body lice?","ar":"ما العلاج الأساسي لقمل الجسم؟"},"options":[{"letter":"A","en":"Bathing and laundering or replacing infested clothing and bedding at high heat","ar":"الاستحمام وغسل أو استبدال الملابس والفراش المصاب بحرارة مرتفعة"},{"letter":"B","en":"Scalp permethrin only","ar":"بيرمثرين لفروة الرأس فقط"},{"letter":"C","en":"Oral antifungal therapy","ar":"مضاد فطري فموي"},{"letter":"D","en":"Intralesional steroids","ar":"ستيرويد داخل الآفة"}],"correct":"A","explanation":{"en":"Body lice live in textiles, so environmental and clothing decontamination is central.","ar":"يعيش قمل الجسم في الأنسجة لذا تعد إزالة تلوث الملابس والبيئة أساس العلاج."},"reasoning":{"en":"The decisive clue is lice and eggs in clothing seams. This supports Bathing and laundering or replacing infested clothing and bedding at high heat and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي القمل والبيض في درزات الملابس؛ ولذلك تدعم الإجابة «الاستحمام وغسل أو استبدال الملابس والفراش المصاب بحرارة مرتفعة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q118","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Treatment","difficulty":"Medium","source":"PDF p. 188","question":{"en":"What is a standard first-line treatment for pubic lice?","ar":"ما علاج خط أول قياسي لقمل العانة؟"},"options":[{"letter":"A","en":"Topical antifungal shampoo only","ar":"شامبو مضاد فطري فقط"},{"letter":"B","en":"Permethrin 1% or pyrethrins with piperonyl butoxide applied to affected hair","ar":"بيرمثرين 1% أو بيريثرينات مع بيبيرونيل بيوتوكسيد على الشعر المصاب"},{"letter":"C","en":"IV acyclovir","ar":"أسيكلوفير وريدي"},{"letter":"D","en":"No partner management","ar":"عدم التعامل مع الشركاء"}],"correct":"B","explanation":{"en":"Pubic lice are treated with a pediculicide and sexual contacts also need evaluation and treatment.","ar":"يُعالج قمل العانة بمبيد قمل مع تقييم وعلاج الشركاء الجنسيين."},"reasoning":{"en":"The decisive clue is visible lice on coarse pubic hair. This supports Permethrin 1% or pyrethrins with piperonyl butoxide applied to affected hair and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي القمل المرئي على شعر العانة الخشن؛ ولذلك تدعم الإجابة «بيرمثرين 1% أو بيريثرينات مع بيبيرونيل بيوتوكسيد على الشعر المصاب» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q119","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Treatment","difficulty":"Medium","source":"PDF p. 188","question":{"en":"How should pubic lice on eyelashes be managed?","ar":"كيف يُعالج قمل العانة الموجود على الرموش؟"},"options":[{"letter":"A","en":"Malathion directly into the eye","ar":"وضع الملاثيون داخل العين"},{"letter":"B","en":"Permethrin on the cornea","ar":"وضع البيرمثرين على القرنية"},{"letter":"C","en":"Mechanical removal plus ophthalmic-grade petrolatum applied carefully","ar":"إزالة ميكانيكية مع فازلين عيني يُوضع بحذر"},{"letter":"D","en":"Oral antibiotics alone","ar":"مضاد حيوي فموي فقط"}],"correct":"C","explanation":{"en":"Standard pediculicides can injure the eye, so ophthalmic-safe local management is required.","ar":"قد تؤذي مبيدات القمل المعتادة العين لذا يلزم علاج موضعي آمن للعين."},"reasoning":{"en":"The decisive clue is eyelash involvement. This supports Mechanical removal plus ophthalmic-grade petrolatum applied carefully and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي إصابة الرموش؛ ولذلك تدعم الإجابة «إزالة ميكانيكية مع فازلين عيني يُوضع بحذر» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q120","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Treatment","difficulty":"Medium","source":"PDF p. 182","question":{"en":"Which oral ivermectin regimen is preferred for resistant head lice in an eligible adult?","ar":"أي نظام إيفرمكتين فموي يُفضل لقمل الرأس المقاوم لدى بالغ مناسب؟"},"options":[{"letter":"A","en":"One gram every hour","ar":"جرام واحد كل ساعة"},{"letter":"B","en":"A single 1-mcg dose","ar":"جرعة واحدة 1 ميكروجرام"},{"letter":"C","en":"Continuous therapy for one year","ar":"علاج مستمر سنة"},{"letter":"D","en":"200 mcg/kg orally, repeated after about 7 days","ar":"200 ميكروجرام/كجم فمويًا مع التكرار بعد نحو 7 أيام"}],"correct":"D","explanation":{"en":"Two appropriately spaced doses cover lice that hatch after the first dose.","ar":"تغطي جرعتان بفاصل مناسب القمل الذي يفقس بعد الجرعة الأولى."},"reasoning":{"en":"The decisive clue is systemic treatment in an eligible resistant case. This supports 200 mcg/kg orally, repeated after about 7 days and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي العلاج الجهازي في حالة مقاومة مناسبة؛ ولذلك تدعم الإجابة «200 ميكروجرام/كجم فمويًا مع التكرار بعد نحو 7 أيام» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q121","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Treatment","difficulty":"Hard","source":"PDF p. 189","question":{"en":"How should combs, bedding, and recently used clothing be handled during head-lice treatment?","ar":"كيف تُعالج الأمشاط والفراش والملابس المستخدمة حديثًا أثناء علاج قمل الرأس؟"},"options":[{"letter":"A","en":"Wash and dry on high heat when possible, or seal unwashable items for about two weeks","ar":"غسل وتجفيف بحرارة مرتفعة عند الإمكان أو إغلاق الأشياء غير القابلة للغسل نحو أسبوعين"},{"letter":"B","en":"Spray the entire home with toxic insecticide fog","ar":"رش المنزل كله بضباب مبيد سام"},{"letter":"C","en":"Burn every household item","ar":"حرق كل أغراض المنزل"},{"letter":"D","en":"No cleaning is ever needed","ar":"لا حاجة لأي تنظيف"}],"correct":"A","explanation":{"en":"Focused decontamination is sufficient; environmental insecticide sprays add risk without benefit.","ar":"تكفي إزالة التلوث الموجهة، بينما تضيف المبيدات المنزلية خطرًا دون فائدة."},"reasoning":{"en":"The decisive clue is short off-host survival with possible attached nits. This supports Wash and dry on high heat when possible, or seal unwashable items for about two weeks and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي قصر البقاء خارج العائل مع احتمال وجود صئبان ملتصقة؛ ولذلك تدعم الإجابة «غسل وتجفيف بحرارة مرتفعة عند الإمكان أو إغلاق الأشياء غير القابلة للغسل نحو أسبوعين» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q122","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Treatment","difficulty":"Hard","source":"PDF p. 189","question":{"en":"When may a child generally return to school after head-lice treatment?","ar":"متى يمكن للطفل عادةً العودة إلى المدرسة بعد علاج قمل الرأس؟"},"options":[{"letter":"A","en":"Only when every nit is removed months later","ar":"فقط بعد إزالة كل صئبان بعد أشهر"},{"letter":"B","en":"After the first appropriate treatment, even if some nits remain","ar":"بعد أول علاج مناسب حتى لو بقيت بعض الصئبان"},{"letter":"C","en":"Never during the same academic year","ar":"لا يعود خلال العام الدراسي"},{"letter":"D","en":"Only after systemic antibiotics","ar":"فقط بعد مضاد حيوي جهازي"}],"correct":"B","explanation":{"en":"Prompt treatment limits transmission, and no-nit policies are not medically justified.","ar":"يحد العلاج السريع من الانتقال ولا تستند سياسات منع العودة بسبب الصئبان إلى مبرر طبي."},"reasoning":{"en":"The decisive clue is treatment completed with no requirement for total nit removal. This supports After the first appropriate treatment, even if some nits remain and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي إكمال العلاج دون اشتراط إزالة كل الصئبان؛ ولذلك تدعم الإجابة «بعد أول علاج مناسب حتى لو بقيت بعض الصئبان» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q123","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Treatment","difficulty":"Hard","source":"PDF p. 193","question":{"en":"Which local strategy is considered highly effective for a small uncomplicated cutaneous leishmaniasis lesion?","ar":"أي استراتيجية موضعية تُعد فعالة جدًا لآفة ليشمانيا جلدية صغيرة غير معقدة؟"},"options":[{"letter":"A","en":"Permethrin cream","ar":"كريم بيرمثرين"},{"letter":"B","en":"Head-lice shampoo","ar":"شامبو قمل الرأس"},{"letter":"C","en":"Cryotherapy combined with intralesional pentavalent antimonial","ar":"العلاج بالتبريد مع حقن مركب الأنتيمون خماسي التكافؤ داخل الآفة"},{"letter":"D","en":"Oral antihistamine alone","ar":"مضاد هيستامين فموي فقط"}],"correct":"C","explanation":{"en":"Combined local destruction and intralesional antiparasitic treatment improves cure in suitable lesions.","ar":"يحسن الجمع بين التدمير الموضعي والعلاج المضاد للطفيليات داخل الآفة الشفاء في الآفات المناسبة."},"reasoning":{"en":"The decisive clue is one small low-risk lesion. This supports Cryotherapy combined with intralesional pentavalent antimonial and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي آفة صغيرة واحدة منخفضة الخطورة؛ ولذلك تدعم الإجابة «العلاج بالتبريد مع حقن مركب الأنتيمون خماسي التكافؤ داخل الآفة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q124","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Treatment","difficulty":"Hard","source":"PDF p. 193","question":{"en":"Which local therapy is useful for small lesions and may be considered during pregnancy or lactation?","ar":"أي علاج موضعي يفيد الآفات الصغيرة وقد يُستخدم أثناء الحمل أو الرضاعة؟"},"options":[{"letter":"A","en":"Oral miltefosine","ar":"ميلتيفوسين فموي"},{"letter":"B","en":"Repeated oral ivermectin","ar":"إيفرمكتين فموي متكرر"},{"letter":"C","en":"Lindane","ar":"ليندان"},{"letter":"D","en":"Thermotherapy","ar":"العلاج الحراري"}],"correct":"D","explanation":{"en":"Thermotherapy avoids systemic fetal drug exposure and can treat selected lesions up to about 25 mm.","ar":"يتجنب العلاج الحراري تعرض الجنين لدواء جهازي ويمكنه علاج آفات مختارة حتى نحو 25 مم."},"reasoning":{"en":"The decisive clue is small localized disease in pregnancy. This supports Thermotherapy and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي مرض موضعي صغير أثناء الحمل؛ ولذلك تدعم الإجابة «العلاج الحراري» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q125","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Treatment","difficulty":"Hard","source":"PDF p. 193","question":{"en":"For which organism is topical paromomycin particularly used?","ar":"لأي نوع يُستخدم الباروموميسين الموضعي بصورة خاصة؟"},"options":[{"letter":"A","en":"Localized cutaneous leishmaniasis caused by Leishmania major","ar":"الليشمانيا الجلدية الموضعية بسبب ليشمانيا ميجور"},{"letter":"B","en":"Scabies caused by Sarcoptes","ar":"الجرب بسبب ساركوبتس"},{"letter":"C","en":"Head lice","ar":"قمل الرأس"},{"letter":"D","en":"CLM caused by hookworm larvae","ar":"هجرة اليرقات بسبب الديدان الخطافية"}],"correct":"A","explanation":{"en":"Paromomycin-containing topical preparations have evidence for selected Old World lesions, especially L. major.","ar":"توجد أدلة على مستحضرات الباروموميسين الموضعية في آفات مختارة من العالم القديم خاصة ليشمانيا ميجور."},"reasoning":{"en":"The decisive clue is species-specific local therapy. This supports Localized cutaneous leishmaniasis caused by Leishmania major and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي العلاج الموضعي الموجه للنوع؛ ولذلك تدعم الإجابة «الليشمانيا الجلدية الموضعية بسبب ليشمانيا ميجور» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q126","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Treatment","difficulty":"Hard","source":"PDF p. 193","question":{"en":"Which patient most clearly requires systemic rather than local treatment?","ar":"أي مريض يحتاج بوضوح إلى علاج جهازي بدلًا من الموضعي؟"},"options":[{"letter":"A","en":"An immunocompetent patient with one 5-mm low-risk lesion","ar":"سليم المناعة بآفة منخفضة الخطورة 5 مم"},{"letter":"B","en":"A patient with mucosal disease, multiple large lesions, high-risk sites, or immunosuppression","ar":"مريض لديه مرض مخاطي أو آفات كبيرة متعددة أو مواقع عالية الخطورة أو تثبيط مناعة"},{"letter":"C","en":"A patient with an inactive scar only","ar":"مريض بندبة غير نشطة فقط"},{"letter":"D","en":"A patient with dandruff","ar":"مريض بقشرة شعر"}],"correct":"B","explanation":{"en":"Complicated disease has higher dissemination, functional, and relapse risks.","ar":"يحمل المرض المعقد مخاطر أكبر للانتشار والضرر الوظيفي والانتكاس."},"reasoning":{"en":"The decisive clue is complicated disease criteria. This supports A patient with mucosal disease, multiple large lesions, high-risk sites, or immunosuppression and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي معايير المرض المعقد؛ ولذلك تدعم الإجابة «مريض لديه مرض مخاطي أو آفات كبيرة متعددة أو مواقع عالية الخطورة أو تثبيط مناعة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q127","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Treatment","difficulty":"Hard","source":"PDF p. 193","question":{"en":"What counseling is mandatory for a woman of childbearing potential receiving miltefosine?","ar":"ما التوعية الإلزامية لامرأة في سن الإنجاب تتلقى ميلتيفوسين؟"},"options":[{"letter":"A","en":"Pregnancy is encouraged during therapy","ar":"يُنصح بالحمل أثناء العلاج"},{"letter":"B","en":"No contraception is needed","ar":"لا حاجة لمنع الحمل"},{"letter":"C","en":"Avoid pregnancy during treatment and for 5 months afterward","ar":"تجنب الحمل أثناء العلاج ولمدة 5 أشهر بعده"},{"letter":"D","en":"Stop all hydration","ar":"إيقاف السوائل"}],"correct":"C","explanation":{"en":"Miltefosine is teratogenic and has a long terminal half-life.","ar":"الميلتيفوسين ماسخ وله عمر نصفي نهائي طويل."},"reasoning":{"en":"The decisive clue is the teratogenic risk and prolonged drug persistence. This supports Avoid pregnancy during treatment and for 5 months afterward and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي خطر التشوه وبقاء الدواء مدة طويلة؛ ولذلك تدعم الإجابة «تجنب الحمل أثناء العلاج ولمدة 5 أشهر بعده» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q128","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Treatment","difficulty":"Hard","source":"PDF p. 193","question":{"en":"Which amphotericin formulation is preferred when a less nephrotoxic systemic option is needed?","ar":"أي تركيبة أمفوتيريسين تُفضل عند الحاجة لخيار جهازي أقل سمية كلوية؟"},"options":[{"letter":"A","en":"Conventional topical amphotericin shampoo","ar":"شامبو أمفوتيريسين موضعي تقليدي"},{"letter":"B","en":"Permethrin 1%","ar":"بيرمثرين 1%"},{"letter":"C","en":"Malathion","ar":"ملاثيون"},{"letter":"D","en":"Liposomal amphotericin B","ar":"أمفوتيريسين ب ليبوسومي"}],"correct":"D","explanation":{"en":"The liposomal formulation reduces renal and infusion toxicity compared with conventional amphotericin.","ar":"تقلل التركيبة الليبوسومية السمية الكلوية وسمية التسريب مقارنة بالأمفوتيريسين التقليدي."},"reasoning":{"en":"The decisive clue is need for systemic efficacy with improved tolerability. This supports Liposomal amphotericin B and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الحاجة لفعالية جهازية مع تحمل أفضل؛ ولذلك تدعم الإجابة «أمفوتيريسين ب ليبوسومي» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q129","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Treatment","difficulty":"Hard","source":"PDF p. 193","question":{"en":"Pentamidine is particularly useful as an alternative for which species complex?","ar":"يُستخدم البنتاميدين خصوصًا كبديل لأي نوع؟"},"options":[{"letter":"A","en":"Leishmania Viannia guyanensis","ar":"ليشمانيا فيانيا جويانينسيس"},{"letter":"B","en":"Sarcoptes scabiei","ar":"ساركوبتس سكابي"},{"letter":"C","en":"Pediculus capitis","ar":"قمل الرأس"},{"letter":"D","en":"Ancylostoma caninum in CLM","ar":"أنكلستوما كانينم في هجرة اليرقات"}],"correct":"A","explanation":{"en":"Pentamidine has a recognized role for selected New World cutaneous disease, especially L. guyanensis.","ar":"للبنتاميدين دور معروف في بعض حالات العالم الجديد خاصة ليشمانيا جويانينسيس."},"reasoning":{"en":"The decisive clue is species-directed systemic selection. This supports Leishmania Viannia guyanensis and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي اختيار جهازي موجه للنوع؛ ولذلك تدعم الإجابة «ليشمانيا فيانيا جويانينسيس» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q130","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Treatment","difficulty":"Hard","source":"PDF p. 193","question":{"en":"Which monitoring is appropriate during systemic pentavalent antimonial therapy?","ar":"أي متابعة مناسبة أثناء العلاج الجهازي بمركبات الأنتيمون خماسية التكافؤ؟"},"options":[{"letter":"A","en":"No monitoring is required","ar":"لا حاجة للمتابعة"},{"letter":"B","en":"ECG plus liver, pancreatic, renal, and blood-count monitoring","ar":"تخطيط قلب مع متابعة الكبد والبنكرياس والكلى وصورة الدم"},{"letter":"C","en":"Only visual acuity once","ar":"حدة البصر مرة واحدة فقط"},{"letter":"D","en":"Only a hair count","ar":"عد الشعر فقط"}],"correct":"B","explanation":{"en":"Antimonials can cause cardiotoxicity, pancreatitis, hepatic injury, marrow effects, and renal problems.","ar":"قد تسبب مركبات الأنتيمون سمية قلبية والتهاب بنكرياس وإصابة كبدية وتأثيرات نخاعية وكلوية."},"reasoning":{"en":"The decisive clue is predictable multisystem toxicity. This supports ECG plus liver, pancreatic, renal, and blood-count monitoring and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي السمية المتوقعة متعددة الأجهزة؛ ولذلك تدعم الإجابة «تخطيط قلب مع متابعة الكبد والبنكرياس والكلى وصورة الدم» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q131","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"Treatment","difficulty":"Hard","source":"PDF p. 198","question":{"en":"What is a standard oral albendazole regimen for uncomplicated cutaneous larva migrans?","ar":"ما نظام ألبيندازول فموي قياسي لهجرة اليرقات الجلدية غير المعقدة؟"},"options":[{"letter":"A","en":"400 mg once monthly","ar":"400 مجم مرة شهريًا"},{"letter":"B","en":"40 mg every hour","ar":"40 مجم كل ساعة"},{"letter":"C","en":"400 mg once daily for 3 days","ar":"400 مجم مرة يوميًا لمدة 3 أيام"},{"letter":"D","en":"Topical use only","ar":"استخدام موضعي فقط"}],"correct":"C","explanation":{"en":"A short albendazole course rapidly stops larval migration and pruritus.","ar":"توقف دورة قصيرة من الألبيندازول هجرة اليرقة والحكة سريعًا."},"reasoning":{"en":"The decisive clue is active symptomatic CLM. This supports 400 mg once daily for 3 days and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي هجرة يرقات نشطة عرضية؛ ولذلك تدعم الإجابة «400 مجم مرة يوميًا لمدة 3 أيام» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q132","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"Treatment","difficulty":"Hard","source":"PDF p. 198","question":{"en":"What is a common ivermectin regimen for an eligible adult with CLM?","ar":"ما نظام الإيفرمكتين الشائع لبالغ مناسب لديه هجرة يرقات جلدية؟"},"options":[{"letter":"A","en":"200 mg/kg every hour","ar":"200 مجم/كجم كل ساعة"},{"letter":"B","en":"One topical drop monthly","ar":"قطرة موضعية شهريًا"},{"letter":"C","en":"Continuous therapy for six months","ar":"علاج مستمر ستة أشهر"},{"letter":"D","en":"200 mcg/kg as a single oral dose, repeated after 24–48 hours if needed","ar":"200 ميكروجرام/كجم جرعة فموية واحدة وتكرر بعد 24–48 ساعة عند الحاجة"}],"correct":"D","explanation":{"en":"Ivermectin is highly effective, and persistent activity may justify one repeat dose.","ar":"الإيفرمكتين عالي الفعالية وقد يستدعي استمرار النشاط جرعة مكررة واحدة."},"reasoning":{"en":"The decisive clue is an eligible adult with a migrating track. This supports 200 mcg/kg as a single oral dose, repeated after 24–48 hours if needed and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي بالغ مناسب لديه مسار مهاجر؛ ولذلك تدعم الإجابة «200 ميكروجرام/كجم جرعة فموية واحدة وتكرر بعد 24–48 ساعة عند الحاجة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q133","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"Treatment","difficulty":"Hard","source":"PDF p. 198","question":{"en":"Which treatment is suitable for one localized CLM lesion during pregnancy when systemic therapy is avoided?","ar":"أي علاج مناسب لآفة واحدة موضعية من هجرة اليرقات أثناء الحمل عند تجنب العلاج الجهازي؟"},"options":[{"letter":"A","en":"Topical thiabendazole 10–15% two or three times daily","ar":"ثيابندازول موضعي 10–15% مرتين أو ثلاث يوميًا"},{"letter":"B","en":"Oral ivermectin","ar":"إيفرمكتين فموي"},{"letter":"C","en":"Lindane","ar":"ليندان"},{"letter":"D","en":"Miltefosine","ar":"ميلتيفوسين"}],"correct":"A","explanation":{"en":"Topical thiabendazole limits systemic exposure and works best for a small number of tracks.","ar":"يحد الثيابندازول الموضعي من التعرض الجهازي ويفيد أكثر مع عدد قليل من المسارات."},"reasoning":{"en":"The decisive clue is localized disease in pregnancy. This supports Topical thiabendazole 10–15% two or three times daily and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي مرض موضعي أثناء الحمل؛ ولذلك تدعم الإجابة «ثيابندازول موضعي 10–15% مرتين أو ثلاث يوميًا» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q134","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"Treatment","difficulty":"Hard","source":"PDF p. 198","question":{"en":"What adjunctive therapy can reduce severe CLM itching while the antiparasitic works?","ar":"ما العلاج المساعد الذي يقلل حكة هجرة اليرقات الشديدة أثناء عمل المضاد للطفيليات؟"},"options":[{"letter":"A","en":"Aspirin applied to open skin","ar":"أسبرين على الجلد المفتوح"},{"letter":"B","en":"An oral antihistamine and a short course of topical corticosteroid when appropriate","ar":"مضاد هيستامين فموي ودورة قصيرة من كورتيكوستيرويد موضعي عند الملاءمة"},{"letter":"C","en":"Antibiotics in every uncomplicated case","ar":"مضاد حيوي لكل حالة غير معقدة"},{"letter":"D","en":"No itch relief should be offered","ar":"لا ينبغي تقديم علاج للحكة"}],"correct":"B","explanation":{"en":"Symptomatic anti-inflammatory care improves comfort but does not replace antiparasitic therapy.","ar":"يحسن العلاج العرضي المضاد للالتهاب الراحة لكنه لا يستبدل العلاج المضاد للطفيليات."},"reasoning":{"en":"The decisive clue is intense pruritus without bacterial infection. This supports An oral antihistamine and a short course of topical corticosteroid when appropriate and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي حكة شديدة دون عدوى بكتيرية؛ ولذلك تدعم الإجابة «مضاد هيستامين فموي ودورة قصيرة من كورتيكوستيرويد موضعي عند الملاءمة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q135","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"Treatment","difficulty":"Hard","source":"PDF p. 199","question":{"en":"Which preventive advice best reduces future CLM risk?","ar":"أي نصيحة وقائية تقلل خطر هجرة اليرقات مستقبلًا؟"},"options":[{"letter":"A","en":"Share towels freely","ar":"مشاركة المناشف بحرية"},{"letter":"B","en":"Walk barefoot where animals defecate","ar":"المشي حافيًا حيث تتبرز الحيوانات"},{"letter":"C","en":"Wear footwear on beaches or contaminated soil and deworm pets","ar":"ارتداء الأحذية على الشواطئ أو التربة الملوثة وعلاج الحيوانات الأليفة من الديدان"},{"letter":"D","en":"Use topical steroids before beach exposure","ar":"استخدام ستيرويد موضعي قبل الشاطئ"}],"correct":"C","explanation":{"en":"Barrier protection and control of animal hookworm reservoirs interrupt skin exposure.","ar":"تقطع الحماية الحاجزية والسيطرة على مستودعات الديدان في الحيوانات طريق تعرض الجلد."},"reasoning":{"en":"The decisive clue is preventing contact with contaminated sand. This supports Wear footwear on beaches or contaminated soil and deworm pets and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي منع التلامس مع الرمل الملوث؛ ولذلك تدعم الإجابة «ارتداء الأحذية على الشواطئ أو التربة الملوثة وعلاج الحيوانات الأليفة من الديدان» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q136","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Image","difficulty":"Easy","source":"PDF p. 168","question":{"en":"The image shows a pruritic papular eruption from the scabies section. Which accompanying history would most strongly support the diagnosis?","ar":"تُظهر الصورة طفحًا حطاطيًا حاكًا من قسم الجرب. أي تاريخ مرضي يدعم التشخيص أكثر؟"},"options":[{"letter":"A","en":"A painless ulcer after a sandfly bite","ar":"قرحة غير مؤلمة بعد لدغة ذبابة الرمل"},{"letter":"B","en":"Nits firmly fixed to hair shafts","ar":"صئبان مثبتة بالشعر"},{"letter":"C","en":"A track advancing 2 cm daily after beach exposure","ar":"مسار يتقدم 2 سم يوميًا بعد الشاطئ"},{"letter":"D","en":"Itching that becomes worse at night and affects close contacts","ar":"حكة تزداد ليلًا وتصيب المخالطين"}],"correct":"D","explanation":{"en":"The rash is nonspecific alone; the nocturnal household pattern makes scabies much more likely.","ar":"الطفح وحده غير نوعي لكن نمط الحكة الليلية بين المخالطين يرجح الجرب بقوة."},"reasoning":{"en":"The decisive clue is the clinical context needed to interpret a nonspecific rash. This supports Itching that becomes worse at night and affects close contacts and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي السياق السريري اللازم لتفسير طفح غير نوعي؛ ولذلك تدعم الإجابة «حكة تزداد ليلًا وتصيب المخالطين» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":"assets/parasitic-q136.webp"},{"id":"Q137","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Image","difficulty":"Easy","source":"PDF p. 168","question":{"en":"Which diagnostic sign should be actively searched for in a patient with the pictured itchy eruption?","ar":"أي علامة تشخيصية ينبغي البحث عنها بفاعلية لدى مريض الطفح الحاك المصور؟"},"options":[{"letter":"A","en":"Burrows in finger webs and on volar wrists","ar":"أنفاق بين الأصابع وعلى السطح الراحي للرسغ"},{"letter":"B","en":"Koplik spots","ar":"بقع كوبليك"},{"letter":"C","en":"Maculae ceruleae only","ar":"البقع الزرقاء الرمادية فقط"},{"letter":"D","en":"Painless indurated ulcers","ar":"قرح غير مؤلمة متصلبة"}],"correct":"A","explanation":{"en":"Burrows are the most specific primary lesion of classic scabies.","ar":"الأنفاق هي الآفة الأولية الأكثر نوعية للجرب التقليدي."},"reasoning":{"en":"The decisive clue is a pruritic eruption requiring confirmation by characteristic sites. This supports Burrows in finger webs and on volar wrists and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي طفح حاك يحتاج التأكيد في المواقع المميزة؛ ولذلك تدعم الإجابة «أنفاق بين الأصابع وعلى السطح الراحي للرسغ» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":"assets/parasitic-q137.webp"},{"id":"Q138","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Image","difficulty":"Easy","source":"PDF p. 169","question":{"en":"What does the fine curved line in the image most likely represent?","ar":"ماذا يمثل الخط الدقيق المنحني في الصورة على الأرجح؟"},"options":[{"letter":"A","en":"A cutaneous larva migrans track advancing centimeters daily","ar":"مسار هجرة يرقات يتقدم سنتيمترات يوميًا"},{"letter":"B","en":"A scabies burrow made by the female mite","ar":"نفق جرب صنعته أنثى العثة"},{"letter":"C","en":"A healed leishmaniasis scar","ar":"ندبة ليشمانيا ملتئمة"},{"letter":"D","en":"A louse egg","ar":"بيضة قمل"}],"correct":"B","explanation":{"en":"A short thread-like burrow in a typical location is pathognomonic for scabies.","ar":"النفق الخيطي القصير في موضع نموذجي علامة نوعية للجرب."},"reasoning":{"en":"The decisive clue is the short superficial thread-like track. This supports A scabies burrow made by the female mite and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي المسار السطحي الخيطي القصير؛ ولذلك تدعم الإجابة «نفق جرب صنعته أنثى العثة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":"assets/parasitic-q138.webp"},{"id":"Q139","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Image","difficulty":"Easy","source":"PDF p. 170","question":{"en":"The widespread atypical eruption shown developed after prolonged corticosteroid use. What is the best diagnosis?","ar":"ظهر الطفح الواسع غير النمطي المصور بعد استخدام مطول للكورتيكوستيرويد. ما التشخيص الأفضل؟"},"options":[{"letter":"A","en":"Crusted scabies","ar":"الجرب المتقشر"},{"letter":"B","en":"Head lice","ar":"قمل الرأس"},{"letter":"C","en":"Scabies incognito","ar":"الجرب المتخفي"},{"letter":"D","en":"Localized cutaneous leishmaniasis","ar":"الليشمانيا الجلدية الموضعية"}],"correct":"C","explanation":{"en":"Steroids suppress the expected inflammatory morphology while permitting the infestation to spread.","ar":"تثبط الستيرويدات الشكل الالتهابي المتوقع بينما تسمح للإصابة بالانتشار."},"reasoning":{"en":"The decisive clue is steroid-modified atypical scabies. This supports Scabies incognito and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الجرب غير النمطي المعدل بالستيرويد؛ ولذلك تدعم الإجابة «الجرب المتخفي» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":"assets/parasitic-q139.webp"},{"id":"Q140","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Image","difficulty":"Easy","source":"PDF p. 171","question":{"en":"The image shows massive hyperkeratotic crusting of the hands in a debilitated patient. Which diagnosis is most likely?","ar":"تُظهر الصورة قشورًا شديدة مفرطة التقرن باليدين لدى مريض واهن. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Scabies in the clean","ar":"الجرب لدى شديدي النظافة"},{"letter":"B","en":"Pediculosis capitis","ar":"قمل الرأس"},{"letter":"C","en":"CLM","ar":"هجرة اليرقات الجلدية"},{"letter":"D","en":"Crusted scabies","ar":"الجرب المتقشر"}],"correct":"D","explanation":{"en":"Crusted scabies produces thick scale with an enormous mite burden and high infectivity.","ar":"يسبب الجرب المتقشر قشورًا سميكة مع حمل هائل من العث وعدوى شديدة."},"reasoning":{"en":"The decisive clue is massive crusting in a high-risk host. This supports Crusted scabies and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي التقشر الهائل لدى عائل عالي الخطورة؛ ولذلك تدعم الإجابة «الجرب المتقشر» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":"assets/parasitic-q140.webp"},{"id":"Q141","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Image","difficulty":"Easy","source":"PDF p. 176","question":{"en":"The magnified ectoparasite shown is adapted to living on human hair and feeding on blood. Which condition does it cause?","ar":"الطفيل الخارجي المكبر في الصورة متكيف للعيش على شعر الإنسان والتغذي على الدم. أي حالة يسبب؟"},"options":[{"letter":"A","en":"Pediculosis","ar":"القمل"},{"letter":"B","en":"Scabies","ar":"الجرب"},{"letter":"C","en":"Leishmaniasis","ar":"الليشمانيا"},{"letter":"D","en":"Cutaneous larva migrans","ar":"هجرة اليرقات الجلدية"}],"correct":"A","explanation":{"en":"The visible six-legged louse is an obligate blood-feeding ectoparasite.","ar":"القملة ذات الأرجل الست الظاهرة طفيل خارجي إجباري يتغذى على الدم."},"reasoning":{"en":"The decisive clue is the morphology of a louse. This supports Pediculosis and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي شكل القملة؛ ولذلك تدعم الإجابة «القمل» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":"assets/parasitic-q141.webp"},{"id":"Q142","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Image","difficulty":"Easy","source":"PDF p. 177","question":{"en":"The image shows numerous small structures fixed to hair shafts near the scalp. What are they?","ar":"تُظهر الصورة أجسامًا صغيرة عديدة مثبتة على سيقان الشعر قرب فروة الرأس. ما هي؟"},"options":[{"letter":"A","en":"Loose dandruff","ar":"قشرة شعر سائبة"},{"letter":"B","en":"Louse eggs (nits)","ar":"بيض القمل (الصئبان)"},{"letter":"C","en":"Scabies eggs within burrows","ar":"بيض الجرب داخل الأنفاق"},{"letter":"D","en":"Leishmania amastigotes","ar":"أماستيغوت الليشمانيا"}],"correct":"B","explanation":{"en":"Nits are cemented to hair shafts and do not brush off like dandruff.","ar":"تلتصق الصئبان بساق الشعرة ولا تسقط مثل القشرة."},"reasoning":{"en":"The decisive clue is firmly adherent oval structures on hair. This supports Louse eggs (nits) and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي أجسام بيضاوية ملتصقة بالشعر؛ ولذلك تدعم الإجابة «بيض القمل (الصئبان)» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":"assets/parasitic-q142.webp"},{"id":"Q143","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Image","difficulty":"Easy","source":"PDF p. 177","question":{"en":"The pictured truncal papules occur when infested clothing is worn, and lice are found in garment seams. Which diagnosis fits best?","ar":"تظهر الحطاطات الجذعية المصورة عند ارتداء ملابس مصابة ويوجد القمل في درزات الثياب. ما التشخيص الأنسب؟"},"options":[{"letter":"A","en":"Pediculosis capitis","ar":"قمل الرأس"},{"letter":"B","en":"Scabies burrows","ar":"أنفاق الجرب"},{"letter":"C","en":"Pediculosis corporis","ar":"قمل الجسم"},{"letter":"D","en":"Localized leishmaniasis","ar":"الليشمانيا الموضعية"}],"correct":"C","explanation":{"en":"Body lice feed on skin but live and lay eggs in clothes.","ar":"يتغذى قمل الجسم على الجلد لكنه يعيش ويضع البيض في الملابس."},"reasoning":{"en":"The decisive clue is clothing-seam infestation with truncal bites. This supports Pediculosis corporis and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي إصابة درزات الملابس مع لدغات على الجذع؛ ولذلك تدعم الإجابة «قمل الجسم» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":"assets/parasitic-q143.webp"},{"id":"Q144","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Image","difficulty":"Easy","source":"PDF p. 178","question":{"en":"What is the name of the bluish-gray macules highlighted in the image of pubic lice infestation?","ar":"ما اسم البقع الزرقاء الرمادية الموضحة في صورة إصابة قمل العانة؟"},"options":[{"letter":"A","en":"Koplik spots","ar":"بقع كوبليك"},{"letter":"B","en":"Rose spots","ar":"البقع الوردية"},{"letter":"C","en":"Burrows","ar":"الأنفاق"},{"letter":"D","en":"Maculae ceruleae","ar":"البقع الزرقاء الرمادية"}],"correct":"D","explanation":{"en":"These bite-site macules result from altered blood pigment and are associated with pubic lice.","ar":"تنشأ هذه البقع في مواضع اللدغ من صبغات الدم المتغيرة وترتبط بقمل العانة."},"reasoning":{"en":"The decisive clue is bluish bite-site pigmentation. This supports Maculae ceruleae and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي التصبغ المزرق في موضع اللدغ؛ ولذلك تدعم الإجابة «البقع الزرقاء الرمادية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":"assets/parasitic-q144.webp"},{"id":"Q145","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Image","difficulty":"Easy","source":"PDF p. 191","question":{"en":"The image shows a chronic ulcer with a raised indurated border on exposed skin. What is the diagnosis?","ar":"تُظهر الصورة قرحة مزمنة بحافة مرتفعة متصلبة على جلد مكشوف. ما التشخيص؟"},"options":[{"letter":"A","en":"Localized cutaneous leishmaniasis","ar":"الليشمانيا الجلدية الموضعية"},{"letter":"B","en":"Classic scabies","ar":"الجرب التقليدي"},{"letter":"C","en":"Head lice","ar":"قمل الرأس"},{"letter":"D","en":"CLM","ar":"هجرة اليرقات الجلدية"}],"correct":"A","explanation":{"en":"This painless volcanic-type ulcer is characteristic of localized cutaneous leishmaniasis.","ar":"هذه القرحة الشبيهة بالفوهة وغير المؤلمة مميزة لليشمانيا الجلدية الموضعية."},"reasoning":{"en":"The decisive clue is the indurated raised ulcer border. This supports Localized cutaneous leishmaniasis and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الحافة القرحيّة المرتفعة المتصلبة؛ ولذلك تدعم الإجابة «الليشمانيا الجلدية الموضعية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":"assets/parasitic-q145.webp"},{"id":"Q146","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Image","difficulty":"Medium","source":"PDF p. 192","question":{"en":"The pictured papules are developing around an old cutaneous leishmaniasis scar. Which variant is shown?","ar":"تظهر الحطاطات المصورة حول ندبة قديمة لليشمانيا الجلدية. أي نمط ظاهر؟"},"options":[{"letter":"A","en":"Diffuse cutaneous leishmaniasis","ar":"الليشمانيا الجلدية المنتشرة"},{"letter":"B","en":"Leishmaniasis recidivans","ar":"الليشمانيا الناكسة"},{"letter":"C","en":"Scabies nodules","ar":"عقيدات الجرب"},{"letter":"D","en":"Body lice dermatitis","ar":"التهاب جلد قمل الجسم"}],"correct":"B","explanation":{"en":"Recidivans represents chronic reactivation at the edge of a healed lesion.","ar":"تمثل الليشمانيا الناكسة إعادة نشاط مزمنة عند حافة آفة ملتئمة."},"reasoning":{"en":"The decisive clue is active papules surrounding an old scar. This supports Leishmaniasis recidivans and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي حطاطات نشطة تحيط بندبة قديمة؛ ولذلك تدعم الإجابة «الليشمانيا الناكسة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":"assets/parasitic-q146.webp"},{"id":"Q147","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Image","difficulty":"Medium","source":"PDF p. 194","question":{"en":"The image shows numerous widespread nonulcerating nodules. Which form of leishmaniasis is most likely?","ar":"تُظهر الصورة عقيدات واسعة عديدة غير متقرحة. أي نوع من الليشمانيا هو الأرجح؟"},"options":[{"letter":"A","en":"One uncomplicated localized lesion","ar":"آفة موضعية واحدة غير معقدة"},{"letter":"B","en":"Mucosal leishmaniasis only","ar":"ليشمانيا مخاطية فقط"},{"letter":"C","en":"Diffuse cutaneous leishmaniasis","ar":"الليشمانيا الجلدية المنتشرة"},{"letter":"D","en":"CLM","ar":"هجرة اليرقات الجلدية"}],"correct":"C","explanation":{"en":"Diffuse disease occurs when cellular immunity fails to contain parasites, producing many lesions.","ar":"يحدث المرض المنتشر عندما تفشل المناعة الخلوية في احتواء الطفيليات فتظهر آفات عديدة."},"reasoning":{"en":"The decisive clue is widespread nonulcerative nodules. This supports Diffuse cutaneous leishmaniasis and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي العقيدات الواسعة غير المتقرحة؛ ولذلك تدعم الإجابة «الليشمانيا الجلدية المنتشرة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":"assets/parasitic-q147.webp"},{"id":"Q148","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Image","difficulty":"Medium","source":"PDF p. 194","question":{"en":"The image demonstrates destructive involvement of the nose and surrounding mucosa. What is the diagnosis?","ar":"توضح الصورة إصابة مدمرة للأنف والأغشية المخاطية المحيطة. ما التشخيص؟"},"options":[{"letter":"A","en":"Pediculosis pubis","ar":"قمل العانة"},{"letter":"B","en":"Crusted scabies","ar":"الجرب المتقشر"},{"letter":"C","en":"Localized CLM","ar":"هجرة يرقات موضعية"},{"letter":"D","en":"Mucosal leishmaniasis","ar":"الليشمانيا المخاطية"}],"correct":"D","explanation":{"en":"Mucosal leishmaniasis can cause severe destructive naso-oropharyngeal disease.","ar":"قد تسبب الليشمانيا المخاطية تخريبًا شديدًا بالأنف والفم والبلعوم."},"reasoning":{"en":"The decisive clue is destructive mucosal anatomy. This supports Mucosal leishmaniasis and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي التخريب في التشريح المخاطي؛ ولذلك تدعم الإجابة «الليشمانيا المخاطية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":"assets/parasitic-q148.webp"},{"id":"Q149","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"Image","difficulty":"Hard","source":"PDF p. 196","question":{"en":"The image shows an intensely pruritic winding track after soil exposure. What is the most likely diagnosis?","ar":"تُظهر الصورة مسارًا متعرجًا شديد الحكة بعد التعرض للتربة. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Cutaneous larva migrans","ar":"هجرة اليرقات الجلدية"},{"letter":"B","en":"A scabies burrow","ar":"نفق جرب"},{"letter":"C","en":"Localized leishmaniasis","ar":"الليشمانيا الموضعية"},{"letter":"D","en":"Body lice bites","ar":"لدغات قمل الجسم"}],"correct":"A","explanation":{"en":"The broad serpiginous creeping eruption reflects migration of an animal hookworm larva.","ar":"يعكس الطفح الزاحف المتعرج العريض هجرة يرقة دودة خطافية حيوانية."},"reasoning":{"en":"The decisive clue is a long advancing serpiginous track. This supports Cutaneous larva migrans and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي مسار متعرج طويل ومتقدم؛ ولذلك تدعم الإجابة «هجرة اليرقات الجلدية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":"assets/parasitic-q149.webp"},{"id":"Q150","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"Image","difficulty":"Hard","source":"PDF p. 196","question":{"en":"The foot lesion shown developed after walking barefoot on a beach. Which counseling point is most important after treatment?","ar":"ظهرت آفة القدم المصورة بعد المشي حافيًا على الشاطئ. ما أهم نصيحة بعد العلاج؟"},"options":[{"letter":"A","en":"Avoid head-to-head contact","ar":"تجنب ملامسة الرأس للرأس"},{"letter":"B","en":"Wear footwear and avoid direct skin contact with sand contaminated by animal feces","ar":"ارتداء الأحذية وتجنب ملامسة الجلد المباشرة للرمل الملوث ببراز الحيوانات"},{"letter":"C","en":"Wash clothing seams for body lice only","ar":"غسل درزات الملابس لقمل الجسم فقط"},{"letter":"D","en":"Use corticosteroids before every beach visit","ar":"استخدام كورتيكوستيرويد قبل كل زيارة للشاطئ"}],"correct":"B","explanation":{"en":"Prevention depends on blocking skin penetration by hookworm larvae in contaminated sand.","ar":"تعتمد الوقاية على منع اختراق يرقات الديدان الخطافية للجلد في الرمل الملوث."},"reasoning":{"en":"The decisive clue is barefoot beach exposure causing a foot track. This supports Wear footwear and avoid direct skin contact with sand contaminated by animal feces and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي التعرض حافيًا على الشاطئ مسببًا مسارًا بالقدم؛ ولذلك تدعم الإجابة «ارتداء الأحذية وتجنب ملامسة الجلد المباشرة للرمل الملوث ببراز الحيوانات» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":"assets/parasitic-q150.webp"}]);
